import type { FC } from 'react';
import { cn } from '@/lib/utils';
import { type IconProps, type SvgProps, sizeMap } from '../types';

export type ShowCurrentFrameProps = IconProps;

const ShowCurrentFrameLight: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <rect x="2" y="3" width="12" height="1" rx=".5" fill="#6C707E" />
    <rect x="2.5" y="6.5" width="11" height="3" rx=".5" stroke="#3574F0" />
    <rect x="2" y="12" width="12" height="1" rx=".5" fill="#6C707E" />
  </svg>
);

const ShowCurrentFrameDark: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <rect x="2" y="3" width="12" height="1" rx=".5" fill="#CED0D6" />
    <rect x="2.5" y="6.5" width="11" height="3" rx=".5" stroke="#548AF7" />
    <rect x="2" y="12" width="12" height="1" rx=".5" fill="#CED0D6" />
  </svg>
);

export const ShowCurrentFrame: FC<ShowCurrentFrameProps> = ({
  size = 'md',
  mode = 'light',
  className,
  'aria-label': ariaLabel,
  title,
  ...props
}) => {
  const SvgComponent =
    mode === 'light' ? ShowCurrentFrameLight : ShowCurrentFrameDark;

  return (
    <SvgComponent
      size={sizeMap[size]}
      className={cn('inline-block flex-shrink-0', className)}
      title={title}
      role={ariaLabel ? 'img' : 'presentation'}
      aria-label={ariaLabel}
      aria-hidden={!ariaLabel}
      {...props}
    />
  );
};
